"""
This module contains the main logic of the Checkers game.
"""

class Piece:
    def __init__(self, color):
        self.color = color  # 'B' for black, 'W' for white
        self.king = False

    def __str__(self):
        return 'K' if self.king else self.color


class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece('B')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('W')

    def move_piece(self, start_pos, end_pos):
        start_x, start_y = start_pos
        end_x, end_y = end_pos
        piece = self.board[start_x][start_y]
        if piece:
            self.board[end_x][end_y] = piece
            self.board[start_x][start_y] = None

    def is_valid_move(self, start_pos, end_pos):
        # Add move validation logic here
        pass


class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, board, start_pos, end_pos):
        if board.is_valid_move(start_pos, end_pos):
            board.move_piece(start_pos, end_pos)
        else:
            print("Invalid move. Try again.")


class GameUI:
    @staticmethod
    def display_board(board):
        for row in board.board:
            print(' '.join([str(piece) if piece else '.' for piece in row]))

    @staticmethod
    def get_user_move():
        return input("Enter your move (from-to): ")


class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.players = [Player('B'), Player('W')]
        self.current_player_index = 0

    def run(self):
        while True:
            GameUI.display_board(self.board)
            start_pos, end_pos = map(int, GameUI.get_user_move().split('-'))
            current_player = self.players[self.current_player_index]
            current_player.make_move(self.board, (start_pos // 8, start_pos % 8), (end_pos // 8, end_pos % 8))
            self.current_player_index = 1 - self.current_player_index
